t.script:
                //
                document.addEventListener('DOMContentLoaded', function() {
                    // Premium one-time welcome curtain
                    const curtain = document.getElementById('welcomeCurtain');
                    const curtainRing = document.getElementById('curtainRing');
                    const params = new URLSearchParams(window.location.search);
                    const forceCurtain = params.get('curtain') === '1';
                    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
                    const alreadySeen = sessionStorage.getItem('cs_welcome_curtain_seen') === '1';

                    if (curtain) {
                        if ((prefersReducedMotion || alreadySeen) && !forceCurtain) {
                            curtain.classList.add('skip');
                            document.body.classList.add('curtain-finished');
                        } else {
                            if (forceCurtain) {
                                sessionStorage.removeItem('cs_welcome_curtain_seen');
                            }
                            curtain.classList.add('awaiting');

                            let opened = false;
                            const openCurtain = () => {
                                if (opened) return;
                                opened = true;
                                curtain.classList.remove('awaiting');
                                curtain.classList.add('play');

                                if (prefersReducedMotion) {
                                    curtain.classList.add('done');
                                    document.body.classList.add('curtain-finished');
                                    sessionStorage.setItem('cs_welcome_curtain_seen', '1');
                                    return;
                                }

                                setTimeout(() => {
                                    curtain.classList.add('done');
                                    document.body.classList.add('curtain-finished');
                                    sessionStorage.setItem('cs_welcome_curtain_seen', '1');
                                }, 2400);
                            };

                            if (curtainRing) {
                                let pulling = false;
                                let startY = 0;
                                let deltaY = 0;

                                const resetPull = function() {
                                    pulling = false;
                                    deltaY = 0;
                                    curtainRing.classList.remove('pulling');
                                    curtainRing.style.transform = '';
                                };

                                curtainRing.addEventListener('pointerdown', function(e) {
                                    if (!e.isTrusted || opened) return;
                                    e.preventDefault();
                                    pulling = true;
                                    startY = e.clientY;
                                    deltaY = 0;
                                    curtainRing.classList.add('pulling');
                                    curtainRing.setPointerCapture(e.pointerId);
                                });

                                curtainRing.addEventListener('pointermove', function(e) {
                                    if (!pulling || opened) return;
                                    deltaY = Math.max(0, Math.min(36, e.clientY - startY));
                                    curtainRing.style.transform = 'translateY(' + deltaY + 'px)';
                                });

                                curtainRing.addEventListener('pointerup', function(e) {
                                    if (!pulling || opened) return;
                                    if (deltaY >= 18) {
                                        openCurtain();
                                    }
                                    if (curtainRing.hasPointerCapture(e.pointerId)) {
                                        curtainRing.releasePointerCapture(e.pointerId);
                                    }
                                    resetPull();
                                });

                                curtainRing.addEventListener('pointercancel', function(e) {
                                    if (curtainRing.hasPointerCapture(e.pointerId)) {
                                        curtainRing.releasePointerCapture(e.pointerId);
                                    }
                                    resetPull();
                                });
                            }
                        }
                    }

                    // Add ripple effect to button
                    const button = document.getElementById('getStartedBtn');

                    button.addEventListener('click', function(e) {
                        const ripple = document.createElement('span');
                        ripple.classList.add('ripple');

                        const rect = this.getBoundingClientRect();
                        const size = Math.max(rect.width, rect.height);
                        const x = e.clientX - rect.left - size / 2;
                        const y = e.clientY - rect.top - size / 2;

                        ripple.style.width = ripple.style.height = size + 'px';
                        ripple.style.left = x + 'px';
                        ripple.style.top = y + 'px';

                        this.appendChild(ripple);

                        setTimeout(() => {
                            ripple.remove();
                        }, 600);
                    });

                    // Add loaded class for animations
                    setTimeout(() => {
                        document.querySelector('.minimal-landing').classList.add('loaded');
                    }, 100);

                    // Parallax effect on mouse move — desktop only
const welcomeBox = document.querySelector('.welcome-box');

if (window.innerWidth > 768) {
    document.addEventListener('mousemove', function(e) {
        const x = (e.clientX / window.innerWidth - 0.5) * 20;
        const y = (e.clientY / window.innerHeight - 0.5) * 20;
        welcomeBox.style.transform = `perspective(1000px) rotateY(${x * 0.1}deg) rotateX(${-y * 0.1}deg)`;
    });
}

                    // Hide scroll indicator on scroll
                    const scrollIndicator = document.querySelector('.scroll-indicator');
                    if (scrollIndicator) {
                        window.addEventListener('scroll', function() {
                            if (window.scrollY > 50) {
                                scrollIndicator.style.opacity = '0';
                            } else {
                                scrollIndicator.style.opacity = '0.7';
                            }
                        });
                    }

                    // Smooth reveal on page load
                    const observer = new IntersectionObserver((entries) => {
                        entries.forEach(entry => {
                            if (entry.isIntersecting) {
                                entry.target.style.opacity = '1';
                                entry.target.style.transform = 'translateY(0)';
                            }
                        });
                    }, {
                        threshold: 0.1
                    });

                    // Add subtle float animation to logo on hover
                    const logoCircle = document.querySelector('.logo-circle');
                    if (logoCircle) {
                        logoCircle.addEventListener('mouseenter', function() {
                            this.style.animation = 'logoGlow 3s ease-in-out infinite, logoFloat 2s ease-in-out infinite';
                        });

                        logoCircle.addEventListener('mouseleave', function() {
                            this.style.animation = 'logoGlow 3s ease-in-out infinite';
                        });
                    }
                });

                // Additional logo float animation
                const style = document.createElement('style');
                style.textContent = `
                    @keyframes logoFloat {
                        0%, 100% {
                            transform: translateY(0) scale(1);
                        }
                        50% {
                            transform: translateY(-10px) scale(1.12);
                        }
                    }
                `;
                document.head.appendChild(style);
                //
